sql:
SELECT pair_name, pair_price, lp_fee
FROM trading_pairs
WHERE base_currency = 'LQ' AND quote_currency = 'ADA';

SELECT SUM(daily_volume) AS TotalTradingVolume
FROM daily_volume
WHERE pair_id = (SELECT pair_id FROM trading_pairs WHERE pair_name = 'SUNDAE/ADA');

SELECT pair_id, pair_name, lp_fee, pair_price
FROM trading_pairs
WHERE pair_price > 10000;

SELECT volume_date, volume_change
FROM daily_volume
WHERE pair_id = 0;

SELECT *
FROM trading_pairs
WHERE pair_price > (SELECT AVG(pair_price) FROM trading_pairs);

SELECT tp.pair_name, tp.pair_price
FROM trading_pairs tp
WHERE tp.pair_price > (SELECT AVG(pair_price) FROM trading_pairs);

external_knowledge:
- Treasuring ADA: In the metaphorical context, holding a treasure chest of more than 100,000 ADA means having a significant amount locked in a trading pair.;
- Navigating the sea of trades: This represents active trading within a market.;
- Current market rates: Refers to the pair_price column, which indicates the current price of the trading pair.;
- Depth of ADA reserves: Refers to the total ADA locked in the trading pair, symbolized as the depth of reserves.;
- Waves of ADA stirred up: This metaphorically describes the volume of ADA traded in the last 24 hours.;

- "under the shadow of a twenty percent threshold" means liquidity provider fee less than 0.2;
- "ocean where large ships weighing in at more than ten thousand tons regularly sail" refers to trading pairs with average trade volumes greater than 10,000;
- "year of the two thousand and twenty-second harvest" indicates the timeframe of January 1, 2022, to December 31, 2022.

sql:
SELECT trading_pairs.pair_name, trade_history.trade_amount
FROM trading_pairs
INNER JOIN trade_history ON trading_pairs.pair_id = trade_history.pair_id;

SELECT pair_name, pair_price 
FROM trading_pairs
ORDER BY pair_name ASC;

SELECT AVG(daily_volume) AS average_daily_volume
FROM daily_volume
WHERE pair_id = 0;

SELECT SUM(dv.daily_volume) AS total_volume_last_7_days
FROM daily_volume dv
WHERE dv.volume_date BETWEEN date('now', '-7 days') AND date('now');

SELECT pair_name, pair_price
FROM trading_pairs
WHERE pair_id = 1;

SELECT pair_name, AVG(lp_fee) AS Average_LP_Fee
FROM trading_pairs
GROUP BY pair_name;

SELECT pair_id
FROM trading_fees
WHERE fee_amount < 0.3;

SELECT AVG(trade_amount) AS average_sell_trade_amount
FROM trade_history
WHERE trade_type = 'sell';

SELECT pair_name 
FROM trading_pairs 
WHERE pair_id = (
    SELECT pair_id 
    FROM daily_volume 
    WHERE daily_volume = (
        SELECT MAX(daily_volume) 
        FROM daily_volume
    )
);

SELECT pair_name, pair_price, created_at
FROM trading_pairs
ORDER BY created_at DESC;
